// // This module implements a synchronous reset D flip-flop using a 2-input LUT. It has four ports: clk, rst, d, and q. The module behaves as follows: when rst is asserted, q is set to 1 regardless of the value of d; when rst is deasserted and a falling edge of clk occurs, q is updated with the value of d.
module sync_reset_dff (
  input clk,
  input rst,
  input d,
  output reg q
);

  always @(posedge clk, negedge rst) begin
    if (~rst) begin
      q <= 1'b0;
    end else begin
      q <= d;
    end
  end

endmodule
